/**
 * File Search Service
 * Public API for file search operations
 *
 * Migration:
 * - Old: @google/generative-ai - File API deleted after 48 hours
 * - New: @google/genai - Persistent File Search Store + fileSearch tool
 *
 * Note: This is a server-only module
 */

// import 'server-only'; // Commented for unit testing

import { logger } from '@/server/lib/logger';
import { ApiError } from '@/server/lib/middleware/error-handler';
import { getGeminiApiKey } from '../config';
import type { FileSearchResult, FileSearchResponse } from '@/types/gemini';
import type { SearchOptions } from './types';
import { loadManifest } from './manifest';
import { performFileSearchStoreSearch } from './file-search-store';
import { getFallbackContext } from './parser';

// Re-export types for backward compatibility
export type { SearchOptions, Manifest, ManifestFile } from './types';

/**
 * Search files using Gemini File Search API and return top results
 *
 * @param query - User search query
 * @param options - Search options (timeout, numResults)
 * @returns FileSearchResponse with results or fallback context
 */
export async function searchFiles(
  query: string,
  options: SearchOptions = {}
): Promise<FileSearchResponse> {
  logger.info({ query }, '[File Search] Starting search');

  const { timeout = 30000, numResults = 3 } = options;

  try {
    const apiKey = getGeminiApiKey();

    if (!apiKey) {
      // Issue #109: Use ApiError for better error handling
      logger.error('[File Search] Gemini API key is not set');
      // Return fallback instead of throwing - maintains user experience
      return {
        success: true,
        results: getFallbackContext(),
      };
    }

    // Load manifest
    const manifest = await loadManifest();

    // Timeout handling with Promise.race
    const searchPromise = performFileSearchStoreSearch(apiKey, query, numResults, manifest);
    const timeoutPromise = new Promise<FileSearchResult[]>((_, reject) =>
      setTimeout(() => reject(ApiError.serviceUnavailable('Search timeout')), timeout)
    );

    const results = await Promise.race([searchPromise, timeoutPromise]);

    return {
      success: true,
      results: results.length > 0 ? results : getFallbackContext(),
    };
  } catch (error) {
    // Issue #109: Structured error logging with ApiError
    if (error instanceof ApiError) {
      logger.warn(
        { code: error.code, message: error.message },
        '[File Search] Expected error occurred'
      );
    } else {
      logger.error({ error }, '[File Search] Unexpected error');
    }

    // Always return fallback context to maintain user experience
    return {
      success: true,
      results: getFallbackContext(),
    };
  }
}

