/**
 * Legacy File Search
 * Fallback search using file parts (for environments without File Search Store)
 */

import { GoogleGenAI } from '@google/genai';
import { logger } from '@/server/lib/logger';
import { getGenerativeModelId } from '../config';
import type { FileSearchResult } from '@/types/gemini';
import type { Manifest, ManifestFile } from './types';
import { buildFileSearchPrompt, extractCategories } from './prompts';
import { parseSearchResults } from './parser';

/**
 * Perform legacy File API search (fallback mode)
 */
export async function performLegacySearch(
  apiKey: string,
  query: string,
  numResults: number,
  manifest: Manifest
): Promise<FileSearchResult[]> {
  try {
    logger.info('[Legacy File Search] Using legacy file parts mode');

    const ai = new GoogleGenAI({ apiKey });

    // Use only web content
    const searchableFiles = manifest.files.filter((f: ManifestFile) => f.source_type === 'web');

    logger.info(
      {
        count: searchableFiles.length,
        files: searchableFiles.map(f => ({ id: f.file_id, name: f.display_name })),
      },
      '[Legacy File Search] Searchable files'
    );

    if (searchableFiles.length === 0) {
      logger.warn('[Legacy File Search] No searchable files found');
      return [];
    }

    // Build file parts
    const fileParts = searchableFiles.map((file: ManifestFile) => ({
      fileData: {
        mimeType: 'text/plain',
        fileUri: `https://generativelanguage.googleapis.com/v1beta/${file.file_id}`,
      },
    }));

    // Extract categories and build prompt (shared with File Search Store)
    const availableCategories = extractCategories(searchableFiles);
    const searchPrompt = buildFileSearchPrompt(query, availableCategories, numResults);

    logger.info('[Legacy File Search] Calling Gemini API');

    // generateContent with file parts
    const response = await ai.models.generateContent({
      model: getGenerativeModelId(),
      contents: [{ text: searchPrompt }, ...fileParts],
      config: {
        temperature: 0.1,
      },
    });

    const text = response.text || '';

    logger.info(
      {
        textLength: text.length,
        preview: text.substring(0, 200),
      },
      '[Legacy File Search] Response'
    );

    const results = parseSearchResults(text, manifest);
    return results.slice(0, numResults);
  } catch (error) {
    logger.error({ error }, '[Legacy File Search] Error');
    return [];
  }
}

