  file_id: string;
  file_search_store_name?: string;
  display_name: string;
  source_type: 'qa' | 'web';
  uploaded_at: string;
  locale?: string;
  category?: string;
  url?: string;
}

export interface Manifest {
  version: string;
  updated_at: string;
  file_search_store_name?: string;
  files: ManifestFile[];
}

/**
 * Search result from parsed response
 */
export interface ParsedSearchResult {
  original_question?: string;
  question?: string;
  answer?: string;
  relevance?: 'high' | 'medium' | 'low';
  source_type?: 'qa' | 'web';
  category?: string;
}
